intent translate_to_korean(text: Text) -> Text {
    goal: translate_text_to_Korean
}

entry main(x: Text) {
    response = perform http.get("https://httpbin.org/json")

    if not response.ok {
        return "Error fetching data"
    }

    parsed = parse_json(response.body)

    if is_error(parsed) {
        return "Error parsing JSON"
    }

    data = unwrap(parsed)
    slideshow = get(data, "slideshow")
    title = get(slideshow, "title")

    korean_title = translate_to_korean(title)
    return korean_title
}

