intent classify_sentiment(text: Text) -> Text {
    goal: positive_or_negative
}

entry main(x: Text) {
    result = perform file.read("/tmp/heaal_e2_data/reviews.txt")
    if is_error(result) {
        return "error reading file"
    }
    content = unwrap(result)
    lines = split(content, "\n")

    positive_count = 0
    negative_count = 0

    for line in lines {
        if length(trim(line)) > 0 {
            sentiment = classify_sentiment(line)
            if sentiment == "positive" {
                positive_count = positive_count + 1
            } else {
                negative_count = negative_count + 1
            }
        }
    }

    return join(["positive=", to_text(positive_count), " negative=", to_text(negative_count)], "")
}

pure fn factorial(n: Number) -> Number {
    if n <= 1 { return 1 }
    return n * factorial(n - 1)
}

entry main(x: Text) {
    result = factorial(10)
    write_result = perform file.write("/tmp/heaal_e2_out/factorial.txt", to_text(result))
    if is_ok(write_result) {
        return "done"
    }
    return "error"
}

intent classify_sentiment(text: Text) -> Text {
    goal: positive_or_negative
}

fn process_reviews() -> Text {
    read_result = perform file.read("/tmp/heaal_e2_data/reviews.txt")
    if is_error(read_result) { return unwrap_error(read_result) }

    content = unwrap(read_result)
    lines = split(content, "\n")

    positives = []
    negatives = []

    for line in lines {
        trimmed = trim(line)
        if length(trimmed) > 0 {
            sentiment = classify_sentiment(trimmed)
            if sentiment == "positive" {
                positives = append(positives, trimmed)
            } else if sentiment == "negative" {
                negatives = append(negatives, trimmed)
            }
        }
    }

    pos_content = join(positives, "\n")
    neg_content = join(negatives, "\n")

    pos_write = perform file.write("/tmp/heaal_e2_out/positives.txt", pos_content)
    if is_error(pos_write) { return unwrap_error(pos_write) }

    neg_write = perform file.write("/tmp/heaal_e2_out/negatives.txt", neg_content)
    if is_error(neg_write) { return unwrap_error(neg_write) }

    return "done"
}

entry main(x: Text) {
    return process_reviews()
}

fn classify_severity(line: Text) -> Text {
    lower_line = lower(line)
    if starts_with(lower_line, "error") { return "ERROR" }
    if starts_with(lower_line, "warn") { return "WARN" }
    if starts_with(lower_line, "info") { return "INFO" }
    return "INFO"
}

entry main(x: Text) {
    content_result = perform file.read("/tmp/heaal_e2_data/log.txt")
    if is_error(content_result) {
        return "ERROR: Could not read file"
    }
    content = unwrap(content_result)
    lines = split(content, "\n")

    info_count = 0
    warn_count = 0
    error_count = 0

    for line in lines {
        if length(trim(line)) > 0 {
            severity = classify_severity(line)
            if severity == "INFO" { info_count = info_count + 1 }
            if severity == "WARN" { warn_count = warn_count + 1 }
            if severity == "ERROR" { error_count = error_count + 1 }
        }
    }

    return join(["INFO=", to_text(info_count), " WARN=", to_text(warn_count), " ERROR=", to_text(error_count)], "")
}

entry main(x: Text) {
    resp = perform http.get("https://httpbin.org/uuid")
    if not resp.ok {
        return "HTTP request failed"
    }
    parsed = parse_json(resp.body)
    if is_error(parsed) {
        return "JSON parse failed"
    }
    data = unwrap(parsed)
    uuid = get(data, "uuid")

    existing = perform file.read("/tmp/heaal_e2_out/uuids.log")
    content = ""
    if existing.ok {
        content = existing.value
    }
    new_content = join([content, uuid, "\n"], "")
    write_result = perform file.write("/tmp/heaal_e2_out/uuids.log", new_content)

    return uuid
}

intent summarize_text(text: Text) -> Text {
    goal: one_sentence_summary_of_input
}

entry main(x: Text) {
    url = "https://en.wikipedia.org/api/rest_v1/page/summary/Claude_(AI)"
    response = perform http.get(url)

    if not response.ok {
        return "Failed to fetch page"
    }

    parsed = parse_json(response.body)
    if is_error(parsed) {
        return "Failed to parse JSON"
    }

    data = unwrap(parsed)
    extract = get(data, "extract")

    return summarize_text(extract)
}
